meta.script:
const modal=document.getElementById('teamModal'),
overlay=modal.querySelector('.team-modal__overlay'),
closeBtns=modal.querySelectorAll('[data-close]'),
imgEl=document.getElementById('teamModalImg'),
nameEl=document.getElementById('teamModalName'),
posEl=document.getElementById('teamModalPosition'),
descEl=document.getElementById('teamModalDesc'),
linkEl=document.getElementById('teamModalLinkedIn');

const teamData={
  ankit:{
    img:"/wp-content/uploads/2024/11/01-3.jpg",
    name:"Ankit Anand",
    position:"Founding Partner",
    desc:"Ankit specializes in expanding Indian deep tech internationally and has experience creating cross-border businesses. 
Why Use DeepTech? believes that innovations being developed in labs today will be the next big thing in India.",
    link:"#"
  },
  mredul:{
    img:"/wp-content/uploads/2024/11/01-3.jpg",
    name:"Mredul Sarda",
    position:"Founding Partner",
    desc:"A former operator who is now an investor with extensive knowledge of research-driven companies. 
Why Use DeepTech? devoted to transforming scientific discoveries into globally scalable businesses.",
    link:"#"
  },
  shubham:{
    img:"/wp-content/uploads/2024/11/01-3.jpg",
    name:"Shubham Raj",
    position:"Founding Partner",
    desc:"Shubham connects science and markets with an emphasis on inclusive growth. 
Why Use DeepTech? believes that deep technologies provide the link that connects economic inclusivity and high-quality research.",
    link:"#"
  },
  lino:{
    img:"/wp-content/uploads/2024/11/01-3.jpg",
    name:"Lino Gandola",
    position:"Founding Partner",
    desc:"Global ecosystem builder and entrepreneur in Asia and Europe. 
Why Use DeepTech? supporters of international cooperation in entrepreneurship and research to further human progress.",
    link:"#"
  }
};

function openModal(data){
  imgEl.src=data.img;
  nameEl.textContent=data.name;
  posEl.textContent=data.position;
  descEl.innerHTML=data.desc;
  linkEl.href=data.link;
  modal.classList.add('show');
  document.body.style.overflow='hidden';
}
function closeModal(){
  modal.classList.remove('show');
  document.body.style.overflow='';
}
overlay.addEventListener('click',closeModal);
closeBtns.forEach(btn=>btn.addEventListener('click',closeModal));
document.addEventListener('keydown',e=>{if(e.key==="Escape")closeModal();});

document.addEventListener('click',function(e){
  const trigger=e.target.closest('[data-member]');
  if(!trigger)return;
  e.preventDefault();
  const slug=trigger.dataset.member;
  const data=teamData[slug];
  if(data)openModal(data);
});

        // Base URL for images - automatically uses WordPress site URL


        // Team members data
        const teamMembers = [
            {
                name: "Ankit Anand",
                role: "Managing Partner",
                location: "Zurich/San Francisco",
                image: "/wp-content/uploads/2025/12/Untitled-1.png",
                linkedin: "https://www.linkedin.com/in/anandvankit/"
            },
            {
                name: "Lino Gandola",
                role: "Managing Partner",
                location: "London",
                image: "/wp-content/uploads/2025/12/lino.jpg",
                linkedin: "https://www.linkedin.com/in/lino-gandola-a13773160/"
            },
            {
                name: "Mredul Sarda",
                role: "General Partner",
                location: "Mumbai",
                image: "/wp-content/uploads/2025/12/Mrudel-Sarda-1.jpg",
                linkedin: "https://www.linkedin.com/in/mredulsarda/"
            },
            {
                name: "Shubham Raj",
                role: "General Partner",
                location: "San Francisco",
                image: "/wp-content/uploads/2025/12/Shubham-Raj.jpg",
                linkedin: "https://www.linkedin.com/in/xceptioncode/"
            },
            {
                name: "Prof Uday Desai",
                role: "Venture Partner",
                location: "Hyderabad",
                image: "/wp-content/uploads/2025/12/11.jpg",
                linkedin: "https://www.linkedin.com/in/ubdesai/"
            },
            {
                name: "Prasad Chaganti",
                role: "Venture Partner",
                location: "London",
                image: "/wp-content/uploads/2025/12/22.jpg",
                linkedin: "https://www.linkedin.com/in/prasad-chaganti-55b7946/"
            },
            {
                name: "Gaurav Lakhwani",
                role: "CMO and Venture Partner",
                location: "Amsterdam",
                image: "/wp-content/uploads/2025/12/33.jpg",
                linkedin: "https://www.linkedin.com/in/gauravlakhwani/"
            },
            {
                name: "Sree Lakshmi",
                role: "Head of Kicksky Space Labs",
                location: "Bangalore",
                image: "/wp-content/uploads/2025/12/44.jpg",
                linkedin: "https://www.linkedin.com/in/sree-lakshmi-b6a387160/"
            },
            {
                name: "Preetham Naik",
                role: "Investment Principal",
                location: "Bangalore",
                image: "/wp-content/uploads/2025/12/Preethamsmall.webp",
                linkedin: "https://www.linkedin.com/in/preethamdnaik/"
            },
            {
                name: "Arushi Sangal",
                role: "Investment Team",
                location: "Delhi",
                image: "/wp-content/uploads/2025/12/55.jpg",
                linkedin: "https://www.linkedin.com/in/arushi-sangal-cfa/"
            },
            {
                name: "Abhinav Gupta",
                role: "Investment Team",
                location: "San Francisco",
                image: "/wp-content/uploads/2025/12/66.jpg",
                linkedin: "https://www.linkedin.com/in/abhinav-22/"
            },
            {
                name: "Joyce Mo",
                role: "Investment Team",
                location: "San Francisco",
                image: "/wp-content/uploads/2025/12/22234e.jpg",
                linkedin: "https://www.linkedin.com/in/joyce-mo/"
            },
            {
                name: "Margaret Cady",
                role: "Investor Relations",
                location: "London",
                image: "/wp-content/uploads/2025/12/888.jpg",
                linkedin: "https://www.linkedin.com/in/margaretholmescady/"
            },
            {
                name: "Archana Anand",
                role: "Operational Team",
                location: "Bangalore",
                image: "/wp-content/uploads/2025/12/99.jpg",
                linkedin: "https://www.linkedin.com/in/archana-anand-509b631b1/"
            }
        ];

        let pos = 0;
        const track = document.getElementById('sliderTrack');
        const total = teamMembers.length;
        let visible = 4;
        let isAnimating = false;

        // Drag functionality
        let isDragging = false;
        let startPos = 0;
        let currentTranslate = 0;
        let prevTranslate = 0;
        let animationID = 0;

        // Create card HTML
        function createCard(member) {
            return `







${member.name}

${member.role}

${member.location}
                    in

            `;
        }

        // Initialize carousel with data
        function initCarousel() {
            track.innerHTML = '';

            // Create cards twice for infinite loop
            for (let i = 0; i < 2; i++) {
                teamMembers.forEach(member => {
                    track.innerHTML += createCard(member);
                });
            }

            // Add drag event listeners
            track.addEventListener('mousedown', dragStart);
            track.addEventListener('touchstart', dragStart);
            track.addEventListener('mouseup', dragEnd);
            track.addEventListener('touchend', dragEnd);
            track.addEventListener('mousemove', drag);
            track.addEventListener('touchmove', drag);
            track.addEventListener('mouseleave', dragEnd);
        }

        function dragStart(e) {
            isDragging = true;
            startPos = e.type.includes('mouse') ? e.pageX : e.touches[0].clientX;
            animationID = requestAnimationFrame(animation);
            track.classList.add('dragging');
        }

        function drag(e) {
            if (!isDragging) return;
            e.preventDefault();

            const currentPosition = e.type.includes('mouse') ? e.pageX : e.touches[0].clientX;
            currentTranslate = prevTranslate + currentPosition - startPos;
        }

        function dragEnd() {
            if (!isDragging) return;

            isDragging = false;
            cancelAnimationFrame(animationID);
            track.classList.remove('dragging');

            const movedBy = currentTranslate - prevTranslate;
            const cardWidth = track.children[0].offsetWidth;
            const gap = 20;

            // Determine if drag was significant enough to move
            if (Math.abs(movedBy) > 100) {
                if (movedBy > 0) {
                    slide(-1); // Dragged right, go previous
                } else {
                    slide(1); // Dragged left, go next
                }
            } else {
                // Snap back to current position
                track.style.transition = 'transform 0.3s ease';
                track.style.transform = `translateX(-${pos * (cardWidth + gap)}px)`;
                setTimeout(() => {
                    track.style.transition = 'transform 0.5s ease';
                }, 300);
            }

            prevTranslate = -pos * (cardWidth + gap);
            currentTranslate = prevTranslate;
        }

        function animation() {
            if (isDragging) {
                track.style.transform = `translateX(${currentTranslate}px)`;
                requestAnimationFrame(animation);
            }
        }

        // Clone cards for infinite loop
        function setupInfiniteLoop() {
            // Already handled in initCarousel
        }

        function updateVisible() {
            const width = window.innerWidth;
            if (width <= 480) visible = 1;
            else if (width <= 768) visible = 2;
            else if (width <= 1200) visible = 3;
            else visible = 4;
        }

        function slide(dir) {
            if (isAnimating) return;

            updateVisible();
            isAnimating = true;
            pos += dir;

            const cardWidth = track.children[0].offsetWidth;
            const gap = 20;
            track.style.transition = 'transform 0.5s ease';
            track.style.transform = `translateX(-${pos * (cardWidth + gap)}px)`;

            prevTranslate = -pos * (cardWidth + gap);
            currentTranslate = prevTranslate;

            setTimeout(() => {
                // Loop forward
                if (pos >= total) {
                    track.style.transition = 'none';
                    pos = 0;
                    track.style.transform = `translateX(0px)`;
                    prevTranslate = 0;
                    currentTranslate = 0;
                }
                // Loop backward
                else if (pos < 0) {
                    track.style.transition = 'none';
                    pos = total - 1;
                    track.style.transform = `translateX(-${pos * (cardWidth + gap)}px)`;
                    prevTranslate = -pos * (cardWidth + gap);
                    currentTranslate = prevTranslate;
                }

                isAnimating = false;
            }, 500);
        }

        window.addEventListener('resize', () => {
            updateVisible();
            const cardWidth = track.children[0].offsetWidth;
            const gap = 20;
            track.style.transition = 'none';
            track.style.transform = `translateX(-${pos * (cardWidth + gap)}px)`;
            setTimeout(() => {
                track.style.transition = 'transform 0.5s ease';
            }, 50);
        });

        initCarousel();
        updateVisible();

